614 |     fn validate_common(&self, operation: &'static str) -> Result<(), AppError> {
615 |         if self.schema_version != SCORE_REPORT_SCHEMA_VERSION {
616 |             return Err(validation_error(
617 |                 ErrorCode::SchemaValidationFailed,
618 |                 "score_report",
619 |                 operation,
620 |                 "unsupported score report schema version",
621 |             ));
622 |         }
623 | 
624 |         validate_identifier(&self.run_id, "score_report.run_id")?;
625 |         validate_identifier(&self.task_id, "score_report.task_id")?;
626 | 
627 |         for score in [
628 |             self.evidence_visibility_score,
629 |             self.evidence_acquisition_score,
630 |             self.evidence_efficiency_score,
631 |             self.explanation_quality_score,
632 |             self.metrics.required_evidence_recall,
633 |             self.metrics.evidence_precision,
634 |             self.metrics.irrelevant_material_ratio,
635 |         ] {
636 |             if !(0.0..=1.0).contains(&score) {
637 |                 return Err(validation_error(
638 |                     ErrorCode::SchemaValidationFailed,
639 |                     "score_report",
640 |                     operation,
641 |                     "all normalized scores and ratios must be between 0.0 and 1.0",
642 |                 ));
643 |             }
644 |         }
645 | 
646 |         Ok(())
647 |     }
648 | }
